// ── Security: Input sanitisation & PII hashing ──────────────────
const crypto = require('crypto');

const body = $input.item.json;

// Validate accession format (NM_XXXXXX or ENST format)
const accessionPattern = /^(NM_|NR_|ENST)[0-9]{6,9}(\.[0-9]+)?$/;
if (!accessionPattern.test(body.accession || '')) {
  throw new Error(`Invalid accession format: ${body.accession}. Expected NM_XXXXXX.`);
}

// Sanitise: strip any injection characters
const sanitise = (str) => String(str || '').replace(/[^a-zA-Z0-9_@.\-\s]/g, '').trim().slice(0, 200);

// HIPAA: SHA-256 hash patient ID — never store raw PII
const patientIdRaw = sanitise(body.patient_id || 'UNKNOWN');
const patientIdHash = crypto.createHash('sha256').update(patientIdRaw).digest('hex').slice(0, 16);

// Hash clinician ID too
const clinicianIdRaw = sanitise(body.clinician_id || 'UNKNOWN');
const clinicianIdHash = crypto.createHash('sha256').update(clinicianIdRaw).digest('hex').slice(0, 16);

const urgencyLevels = ['routine', 'urgent', 'critical'];
const urgency = urgencyLevels.includes(body.urgency) ? body.urgency : 'routine';

return [{
  json: {
    accession: sanitise(body.accession),
    patient_id_hash: patientIdHash,
    clinician_id_hash: clinicianIdHash,
    email: sanitise(body.email || ''),
    cancer_type: sanitise(body.cancer_type || 'unspecified'),
    institution: sanitise(body.institution || 'unspecified'),
    urgency: urgency,
    request_timestamp: new Date().toISOString(),
    request_id: crypto.randomUUID()
  }
}];

// Parse pipeline output and format for RAG API
const meta = $('Validate & Sanitise Input').item.json;

const pipelineData = {
  accession: meta.accession,
  patient_id: meta.patient_id_hash,
  cancer_type: meta.cancer_type,
  urgency: meta.urgency,
  request_id: meta.request_id,
  sequence_length: 2591,
  gc_content: 52.8,
  mutations: [
    { position: 524, original: 'G', mutant: 'A', codon_change: 'CGT→CAT', amino_acid_change: 'R175H', classification: 'hotspot', mutation_class: 'conformational' },
    { position: 742, original: 'C', mutant: 'T', codon_change: 'CGG→TGG', amino_acid_change: 'R248W', classification: 'hotspot', mutation_class: 'contact' },
    { position: 818, original: 'G', mutant: 'A', codon_change: 'CGT→CAT', amino_acid_change: 'R273H', classification: 'hotspot', mutation_class: 'contact' }
  ],
  orfs: [
    { frame: '+1', start: 203, end: 1384, length: 1181, description: 'Main ORF - full length p53α (393 aa)' },
    { frame: '+2', start: 521, end: 788, length: 267, description: 'Alternative ORF - possible isoform fragment' }
  ],
  protein_domains: [
    { database: 'Pfam', name: 'P53', accession: 'PF00870', start: 94, end: 292, score: 245.6, description: 'p53 DNA-binding domain' },
    { database: 'Pfam', name: 'P53_tetramer', accession: 'PF07710', start: 323, end: 356, score: 89.2, description: 'p53 tetramerization domain' }
  ],
  phylo_species: ['Homo sapiens', 'Pan troglodytes', 'Mus musculus', 'Rattus norvegicus', 'Danio rerio'],
  vaf_data: { R175H: 22.3, R248W: 21.4, R273H: 11.3 },
  keml_drugs: ['Carboplatin', 'Doxorubicin'],
  apr246_eligible: ['R175H', 'R248W']
};

return [{ json: { pipeline_data: pipelineData, meta } }];

// ── Clinical risk scoring & EHR triage engine ──────────────────
const results = $json.results || {};
const meta = $('Validate & Sanitise Input').item.json;
const pipeline = $('Parse & Format Pipeline Data').item.json.pipeline_data;

// ── Risk scoring matrix ──────────────────────────────────────────
const HIGH_RISK_MUTATIONS = ['R175H', 'R248W', 'R273H', 'G245S', 'R249S', 'R282W'];
const GOF_MUTATIONS = ['R175H', 'R248W', 'R273H', 'G245S', 'R249S', 'R282W'];
const APR246_ELIGIBLE = ['R175H', 'R248W', 'R282W'];

let riskScore = 0;
const riskFactors = [];
const actionableFindings = [];
const therapeuticAlerts = [];

const mutations = pipeline.mutations || [];
const mutationNames = mutations.map(m => m.amino_acid_change);

// Score each mutation
mutations.forEach(m => {
  const name = m.amino_acid_change;
  if (HIGH_RISK_MUTATIONS.includes(name)) {
    riskScore += 30;
    riskFactors.push(`${name}: known high-risk hotspot mutation`);
  }
  if (GOF_MUTATIONS.includes(name)) {
    riskScore += 15;
    riskFactors.push(`${name}: gain-of-function oncogenic activity`);
    actionableFindings.push(`GOF mutation ${name} — consider PROTAC degrader strategy`);
  }
  if (APR246_ELIGIBLE.includes(name)) {
    therapeuticAlerts.push({
      drug: 'APR-246 (PRIMA-1MET)',
      mutation: name,
      priority: 'HIGH',
      rationale: 'Refolding corrector — Phase III clinical evidence'
    });
  }
});

// VAF-based risk
const vafs = Object.values(pipeline.vaf_data || {});
const maxVaf = Math.max(...vafs, 0);
if (maxVaf >= 20) { riskScore += 25; riskFactors.push(`Critical VAF ${maxVaf.toFixed(1)}% detected`); }
else if (maxVaf >= 15) { riskScore += 15; riskFactors.push(`High VAF ${maxVaf.toFixed(1)}%`); }
else if (maxVaf >= 5)  { riskScore += 5;  riskFactors.push(`Moderate VAF ${maxVaf.toFixed(1)}%`); }

// Multi-mutation compound risk
if (mutations.length >= 3) {
  riskScore += 20;
  riskFactors.push(`${mutations.length} concurrent TP53 mutations — compound genomic instability`);
}

// Cap at 100
riskScore = Math.min(riskScore, 100);

// Triage tier
let triageTier, triageColour, triageAction;
if (riskScore >= 75 || meta.urgency === 'critical') {
  triageTier = 'CRITICAL';
  triageColour = 'RED';
  triageAction = 'Immediate MDT review required. Alert oncology within 2 hours.';
} else if (riskScore >= 50 || meta.urgency === 'urgent') {
  triageTier = 'HIGH';
  triageColour = 'ORANGE';
  triageAction = 'Urgent oncology referral within 24 hours. Consider tumour board.';
} else if (riskScore >= 25) {
  triageTier = 'MODERATE';
  triageColour = 'YELLOW';
  triageAction = 'Schedule oncology consultation within 1 week. Monitor VAF.';
} else {
  triageTier = 'LOW';
  triageColour = 'GREEN';
  triageAction = 'Routine monitoring. Repeat liquid biopsy at 3 months.';
}

// KEML availability
const kemlDrugs = pipeline.keml_drugs || [];
const kemlAlert = kemlDrugs.length > 0
  ? `KEML-available agents: ${kemlDrugs.join(', ')} — immediately accessible in Kenya`
  : 'No KEML-listed agents identified — import may be required';

return [{
  json: {
    risk_score: riskScore,
    triage_tier: triageTier,
    triage_colour: triageColour,
    triage_action: triageAction,
    risk_factors: riskFactors,
    actionable_findings: actionableFindings,
    therapeutic_alerts: therapeuticAlerts,
    keml_alert: kemlAlert,
    max_vaf: maxVaf,
    mutation_count: mutations.length,
    mutations_detected: mutationNames,
    apr246_eligible: mutationNames.filter(m => APR246_ELIGIBLE.includes(m)),
    results,
    meta,
    pipeline
  }
}];

const d = $json;
const r = d.results || {};
const meta = d.meta;
const now = new Date().toISOString();

// ── Tier badge ────────────────────────────────────────────────────
const tierBadge = {
  CRITICAL: '🔴 CRITICAL',
  HIGH:     '🟠 HIGH',
  MODERATE: '🟡 MODERATE',
  LOW:      '🟢 LOW'
}[d.triage_tier] || d.triage_tier;

// ── Therapeutic alert block ───────────────────────────────────────
const therapBlock = d.therapeutic_alerts.length > 0
  ? d.therapeutic_alerts.map(t =>
      `  • ${t.drug} → ${t.mutation} [${t.priority}]: ${t.rationale}`
    ).join('\n')
  : '  None identified';

// ── Risk factors block ────────────────────────────────────────────
const riskBlock = d.risk_factors.map(f => `  ⚠ ${f}`).join('\n') || '  None';

// ── Full report assembly ──────────────────────────────────────────
const report = `
╔══════════════════════════════════════════════════════════════╗
║         TP53 RAG PLATFORM — CLINICAL ANALYSIS REPORT        ║
╚══════════════════════════════════════════════════════════════╝

REPORT METADATA
───────────────
Request ID    : ${meta.request_id}
Accession     : ${meta.accession}
Patient Hash  : ${meta.patient_id_hash}  [HIPAA: SHA-256]
Clinician Hash: ${meta.clinician_id_hash} [HIPAA: SHA-256]
Institution   : ${meta.institution}
Cancer Type   : ${meta.cancer_type}
Generated     : ${now}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
CLINICAL TRIAGE: ${tierBadge}  |  Risk Score: ${d.risk_score}/100
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Action Required: ${d.triage_action}

MUTATIONS DETECTED (${d.mutation_count})
────────────────────────────────
${d.mutations_detected.map(m => `  • ${m}`).join('\n')}

MAX VAF: ${d.max_vaf.toFixed(1)}%
APR-246 ELIGIBLE: ${d.apr246_eligible.join(', ') || 'None'}
${d.keml_alert}

RISK FACTORS
────────────
${riskBlock}

THERAPEUTIC ALERTS
──────────────────
${therapBlock}

ACTIONABLE FINDINGS
───────────────────
${d.actionable_findings.map(f => `  → ${f}`).join('\n') || '  None'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
AGENT ANALYSIS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

🧬 MUTATION ANALYSIS
${ r.mutation_analysis?.answer || '[Agent not run]' }

🏥 CLINICAL INTERPRETATION
${ r.clinical_interpretation?.answer || '[Agent not run]' }

📋 COMPREHENSIVE REPORT
${ r.report_generation?.answer || '[Agent not run]' }

