DISCLAIMER
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
This report is generated by an AI research platform and must be
confirmed by a CLIA-certified laboratory before clinical action.
All patient identifiers are SHA-256 hashed. HIPAA compliant.
HL7 FHIR R4 structured output available via /fhir endpoint.
`;

return [{ json: { report, triage_tier: d.triage_tier, triage_colour: d.triage_colour, risk_score: d.risk_score, meta, therapeutic_alerts: d.therapeutic_alerts, apr246_eligible: d.apr246_eligible } }];

// ══════════════════════════════════════════════════════════════════
// EHR ALERT ENGINE — TP53 RAG Platform
// Generates HL7 FHIR R4 compliant alerts + multi-channel notifications
// Covers: CRITICAL / HIGH / MODERATE / LOW triage tiers
// ══════════════════════════════════════════════════════════════════
const crypto = require('crypto');

const d = $json;
const meta = d.meta;
const now = new Date().toISOString();
const alertId = crypto.randomUUID();

// ── 1. HL7 FHIR R4 ClinicalImpression resource ────────────────────
const fhirAlert = {
  resourceType: 'Bundle',
  id: alertId,
  type: 'collection',
  timestamp: now,
  entry: [
    {
      fullUrl: `urn:uuid:${crypto.randomUUID()}`,
      resource: {
        resourceType: 'ClinicalImpression',
        id: alertId,
        status: 'completed',
        description: `TP53 Multi-Hotspot Analysis — Triage: ${d.triage_tier}`,
        subject: { reference: `Patient/${meta.patient_id_hash}` },
        assessor: { reference: `Practitioner/${meta.clinician_id_hash}` },
        date: now,
        summary: `Risk score ${d.risk_score}/100. Triage tier: ${d.triage_tier}. ${d.therapeutic_alerts.length} therapeutic targets identified.`,
        finding: d.therapeutic_alerts.map(t => ({
          itemCodeableConcept: {
            coding: [{ system: 'http://snomed.info/sct', display: t.drug }],
            text: `${t.drug} — Priority: ${t.priority}`
          },
          basis: t.rationale
        }))
      }
    },
    {
      fullUrl: `urn:uuid:${crypto.randomUUID()}`,
      resource: {
        resourceType: 'Flag',
        id: crypto.randomUUID(),
        status: d.triage_tier === 'CRITICAL' ? 'active' : 'inactive',
        category: [{
          coding: [{ system: 'http://terminology.hl7.org/CodeSystem/flag-category', code: 'clinical', display: 'Clinical' }]
        }],
        code: {
          coding: [{ system: 'http://snomed.info/sct', code: '416940007', display: 'TP53 Mutation Alert' }],
          text: `TP53 ${d.triage_tier} Alert — ${meta.accession}`
        },
        subject: { reference: `Patient/${meta.patient_id_hash}` },
        period: { start: now },
        author: { reference: 'Device/TP53-RAG-Platform-v1' }
      }
    },
    {
      fullUrl: `urn:uuid:${crypto.randomUUID()}`,
      resource: {
        resourceType: 'DiagnosticReport',
        id: crypto.randomUUID(),
        status: 'final',
        category: [{
          coding: [{ system: 'http://terminology.hl7.org/CodeSystem/v2-0074', code: 'GE', display: 'Genetics' }]
        }],
        code: {
          coding: [{ system: 'http://loinc.org', code: '51969-4', display: 'Genetic analysis summary report' }],
          text: 'TP53 Multi-Agent Genomic Analysis'
        },
        subject: { reference: `Patient/${meta.patient_id_hash}` },
        issued: now,
        conclusion: `${d.triage_tier} risk. ${d.therapeutic_alerts.length} actionable therapeutic targets. Risk score: ${d.risk_score}/100.`,
        conclusionCode: [{
          coding: [{
            system: 'http://snomed.info/sct',
            code: d.triage_tier === 'CRITICAL' ? '415068001' : '10828004',
            display: d.triage_tier === 'CRITICAL' ? 'Positive finding' : 'Finding'
          }]
        }]
      }
    }
  ]
};

// ── 2. Smart notification routing by triage tier ──────────────────
const notifications = [];

if (d.triage_tier === 'CRITICAL') {
  notifications.push(
    { channel: 'sms',   priority: 'IMMEDIATE', recipient: meta.clinician_id_hash, message: `🔴 CRITICAL TP53 ALERT — Patient ${meta.patient_id_hash.slice(0,8)}\nRisk: ${d.risk_score}/100 | ${meta.accession}\nImmediate MDT review required.\nTherapeutic: ${d.therapeutic_alerts.map(t=>t.drug).join(', ') || 'See report'}` },
    { channel: 'email', priority: 'IMMEDIATE', recipient: meta.email, subject: `🔴 CRITICAL TP53 Alert — ${meta.accession}` },
    { channel: 'ehr_flag', priority: 'IMMEDIATE', flag_colour: 'RED', flag_text: `CRITICAL TP53 — ${d.risk_score}/100 — MDT REQUIRED` },
    { channel: 'pager', priority: 'IMMEDIATE', message: `TP53 CRITICAL: ${meta.accession}` }
  );
} else if (d.triage_tier === 'HIGH') {
  notifications.push(
    { channel: 'email', priority: 'URGENT', recipient: meta.email, subject: `🟠 HIGH TP53 Alert — ${meta.accession}` },
    { channel: 'ehr_flag', priority: 'URGENT', flag_colour: 'ORANGE', flag_text: `HIGH TP53 — ${d.risk_score}/100 — 24HR REFERRAL` },
    { channel: 'slack', priority: 'URGENT', message: `🟠 HIGH TP53 finding: ${meta.accession} | Risk: ${d.risk_score}/100 | Patient: ${meta.patient_id_hash.slice(0,8)}` }
  );
} else if (d.triage_tier === 'MODERATE') {
  notifications.push(
    { channel: 'email', priority: 'STANDARD', recipient: meta.email, subject: `🟡 MODERATE TP53 Finding — ${meta.accession}` },
    { channel: 'ehr_flag', priority: 'STANDARD', flag_colour: 'YELLOW', flag_text: `MODERATE TP53 — ${d.risk_score}/100 — REVIEW WITHIN 1 WEEK` }
  );
} else {
  notifications.push(
    { channel: 'email', priority: 'ROUTINE', recipient: meta.email, subject: `🟢 TP53 Analysis Complete — ${meta.accession}` },
    { channel: 'ehr_flag', priority: 'ROUTINE', flag_colour: 'GREEN', flag_text: `LOW RISK TP53 — ${d.risk_score}/100 — ROUTINE MONITORING` }
  );
}

// ── 3. Audit trail (HIPAA append-only) ───────────────────────────
const auditEntry = {
  event_id: crypto.randomUUID(),
  timestamp: now,
  event_type: 'EHR_ALERT_DISPATCHED',
  alert_id: alertId,
  triage_tier: d.triage_tier,
  risk_score: d.risk_score,
  accession: meta.accession,
  patient_id_hash: meta.patient_id_hash,
  clinician_id_hash: meta.clinician_id_hash,
  institution: meta.institution,
  notification_channels: notifications.map(n => n.channel),
  therapeutic_targets: d.therapeutic_alerts.length,
  apr246_eligible: d.apr246_eligible,
  hipaa_compliant: true,
  fhir_version: 'R4'
};

// ── 4. Kenya/Africa clinical context enrichment ───────────────────
const africaContext = {
  keml_available: d.therapeutic_alerts
    .filter(t => ['Carboplatin', 'Doxorubicin'].includes(t.drug))
    .map(t => t.drug),
  import_required: d.therapeutic_alerts
    .filter(t => !['Carboplatin', 'Doxorubicin'].includes(t.drug))
    .map(t => t.drug),
  clinical_trial_referral: d.triage_tier !== 'LOW'
    ? 'Consider AORTIC (African Organisation for Research & Training in Cancer) trials registry'
    : null,
  nairobi_oncology_centres: d.triage_tier === 'CRITICAL'
    ? ['Kenyatta National Hospital — Oncology', 'Aga Khan University Hospital — Cancer Centre', 'Nairobi Hospital — Oncology Unit']
    : []
};

return [{
  json: {
    alert_id: alertId,
    triage_tier: d.triage_tier,
    risk_score: d.risk_score,
    fhir_bundle: fhirAlert,
    notifications,
    audit_trail: auditEntry,
    africa_context: africaContext,
    report: d.report,
    meta
  }
}];

// ── Platform unavailable — generate fallback alert ───────────────
const crypto = require('crypto');
const meta = $('Validate & Sanitise Input').item.json;
const now = new Date().toISOString();

const fallbackAlert = {
  alert_type: 'PLATFORM_UNAVAILABLE',
  severity: 'SYSTEM_ERROR',
  timestamp: now,
  request_id: meta.request_id,
  accession: meta.accession,
  patient_id_hash: meta.patient_id_hash,
  message: 'TP53 RAG Platform is offline. Analysis cannot be completed.',
  recommended_action: 'Check that the FastAPI server is running: python main.py serve',
  fallback_resources: [
    'IARC TP53 Database: https://tp53.isb-cgc.org',
    'ClinVar TP53: https://clinvar.ncbi.nlm.nih.gov/gene/7157',
    'COSMIC TP53: https://cancer.sanger.ac.uk/gene/TP53'
  ],
  retry_webhook: `http://localhost:5678/webhook/tp53-analysis`,
  estimated_downtime: 'Check server logs at /logs/rag_platform.log',
  hipaa_compliant: true,
  audit_event: {
    event_id: crypto.randomUUID(),
    event_type: 'PLATFORM_UNAVAILABLE_ALERT',
    timestamp: now,
    accession: meta.accession,
    patient_id_hash: meta.patient_id_hash
  }
};

console.error(`[TP53 RAG] Platform unavailable for request ${meta.request_id} — accession ${meta.accession}`);

return [{ json: fallbackAlert }];
